    "home.cta.science": "Explore the Science",
    "home.card.metabolic": "Metabolic Switch",
    "home.card.metabolic.desc": "Shift from glucose to fat metabolism for sustained energy.",
    "home.benefits.title": "More Than Just Weight Loss",
